html = []
def w(s): html.append(s)

w('<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>青柠漫画 · 项目展示</title>\n<style>\n*{margin:0;padding:0;box-sizing:border-box;}\nbody{background:#000;display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;font-family:"PingFang SC","Microsoft YaHei","Segoe UI",sans-serif;overflow:hidden;}\n#stage{position:relative;width:100vw;height:100vh;display:flex;align-items:center;justify-content:center;}\n.slide-canvas{width:1920px;height:1080px;background:#0a0a0f;color:#e2e8f0;position:absolute;transform-origin:center center;display:none;flex-direction:column;padding:60px 80px;overflow:hidden;}\n.slide-canvas.active{display:flex;}\nh1{font-size:72px;font-weight:700;color:#4ade80;letter-spacing:2px;line-height:1.2;}\nh2{font-size:46px;font-weight:600;color:#4ade80;margin-bottom:24px;letter-spacing:1px;}\nh3{font-size:28px;font-weight:600;color:#86efac;margin-bottom:12px;}\np{font-size:21px;line-height:1.8;color:#cbd5e1;margin-bottom:12px;}\n.subtitle{font-size:32px;color:#94a3b8;margin-top:16px;}\n.subsubtitle{font-size:22px;color:#64748b;margin-top:10px;}\n.info-table{margin-top:36px;border-collapse:collapse;width:760px;}\n.info-table td{padding:10px 20px;font-size:19px;color:#94a3b8;border:1px solid #1e293b;}\n.info-table td:first-child{color:#4ade80;font-weight:600;white-space:nowrap;background:#0f172a;}\n.info-table tr:nth-child(even) td{background:#0d1117;}\n.code-block{background:#0d1117;border:1px solid #4ade80;border-radius:6px;padding:16px 20px;font-family:"Cascadia Code","Fira Code",Consolas,monospace;font-size:14px;color:#86efac;white-space:pre;overflow:hidden;line-height:1.5;flex-shrink:0;}\n.code-block.arch{font-size:13px;}\ntable{border-collapse:collapse;width:100%;font-size:18px;margin-bottom:14px;}\nthead tr{background:#0f172a;}\nthead th{color:#4ade80;padding:9px 14px;text-align:left;border:1px solid #1e293b;font-weight:600;}\ntbody tr:nth-child(odd){background:#0a0f1a;}\ntbody tr:nth-child(even){background:#0d1117;}\ntbody td{padding:8px 14px;color:#cbd5e1;border:1px solid #1e293b;vertical-align:top;line-height:1.55;}\nblockquote{border-left:3px solid #4ade80;padding:8px 18px;background:#0f172a;color:#86efac;font-size:19px;margin:10px 0;border-radius:0 4px 4px 0;}\n.flow-wrap{display:flex;flex-direction:column;gap:8px;margin:16px 0;}\n.flow-row{display:flex;align-items:center;flex-wrap:nowrap;gap:0;}\n.flow-step{background:#0f172a;border:1px solid #4ade80;border-radius:5px;padding:8px 14px;font-size:16px;color:#e2e8f0;white-space:nowrap;text-align:center;}\n.flow-arrow{color:#4ade80;font-size:20px;padding:0 5px;flex-shrink:0;}\n.two-col{display:flex;gap:36px;flex:1;min-height:0;}\n.col{flex:1;min-width:0;display:flex;flex-direction:column;}\n.label{font-size:12px;color:#4ade80;letter-spacing:3px;text-transform:uppercase;margin-bottom:6px;}\n#nav-dots{position:fixed;bottom:16px;left:50%;transform:translateX(-50%);display:flex;gap:8px;z-index:100;}\n.dot{width:8px;height:8px;border-radius:50%;background:#334155;cursor:pointer;transition:background .2s;}\n.dot.active{background:#4ade80;}\n#nav-prev,#nav-next{position:fixed;bottom:8px;z-index:100;background:#0f172a;border:1px solid #334155;color:#94a3b8;padding:5px 16px;border-radius:4px;cursor:pointer;font-size:13px;transition:border-color .2s,color .2s;}\n#nav-prev{left:calc(50% - 110px);}\n#nav-next{right:calc(50% - 110px);}\n#nav-prev:hover,#nav-next:hover{border-color:#4ade80;color:#4ade80;}\n#slide-counter{position:fixed;top:14px;right:22px;color:#334155;font-size:13px;z-index:100;}\n.cover-center{flex:1;display:flex;flex-direction:column;justify-content:center;align-items:flex-start;}\n.cover-line{width:60px;height:3px;background:#4ade80;margin:18px 0;}\n.gap{margin-bottom:10px;}\n</style>\n</head>\n<body>\n<div id="stage">')

w('\n<!-- SLIDE 1: Cover -->\n<div class="slide-canvas active" id="slide-1">\n  <div class="cover-center">\n    <div class="label">QingningComic</div>\n    <h1>青柠漫画</h1>\n    <div class="cover-line"></div>\n    <div class="subtitle">小说转漫画创作平台</div>\n    <div class="subsubtitle">QingningComic &middot; 小说转漫画创作平台</div>\n    <table class="info-table">\n      <tr><td>语言 / GUI</td><td>C++11 &middot; Qt 5.15.2 LTS</td></tr>\n      <tr><td>数据库</td><td>MySQL 8.0（CentOS VM）</td></tr>\n      <tr><td>AI 服务</td><td>阿里云 Qwen &middot; 阿里云 DashScope &middot; 火山引擎</td></tr>\n      <tr><td>存储</td><td>本地磁盘（local 模式）</td></tr>\n    </table>\n  </div>\n</div>')

w('\n<!-- SLIDE 2: Background -->\n<div class="slide-canvas" id="slide-2">\n  <h2>项目背景与目标</h2>\n  <p>漫画创作门槛高，小说作者难以将文字内容快速可视化，手工绘制分镜耗时耗力。青柠漫画提供小说管理、AI 分析（Qwen 解析剧情生成结构化分镜脚本）、角色 &amp; 场景圣经自动提取、双引擎图片生成（阿里云 DashScope / 火山引擎）、自然语言图片编辑、多格式导出（PDF / Webtoon / 资源包）。目标用户为漫画创作者、小说作者和同人内容创作者。</p>\n</div>')

w('\n<!-- SLIDE 3: Architecture -->\n<div class="slide-canvas" id="slide-3">\n  <h2>整体架构</h2>\n  <div class="code-block arch">┌─────────────────────────────────────────────────────────────────┐\n│                    UI 层  (Qt Widgets)                          │\n│                                                                 │\n│  LoginPage  DashboardPage  NovelPage  NovelDetailPage          │\n│  NovelUploadPage  ExportPage  CharacterDetailPage              │\n└──────────────────────────┬──────────────────────────────────────┘\n                           │  Qt 信号 / 槽\n┌──────────────────────────▼──────────────────────────────────────┐\n│                  ViewModel 层                                   │\n│          NovelViewModel        StoryboardViewModel              │\n└──────────────────────────┬──────────────────────────────────────┘\n                           │\n┌──────────────────────────▼──────────────────────────────────────┐\n│                   服务层  (Business Logic)                      │\n│                                                                 │\n│  AnalysisService   StoryboardService   NovelService            │\n│  BibleGenerator    ImageService        ExportService           │\n│  CharacterExtractor   SceneExtractor                           │\n└──────────┬───────────────────────────────────┬──────────────────────┘\n           │                               │\n┌──────────▼───────────────────┐  ┌─────────▼────────────────────────┐\n│   API 客户端层              │  │         数据层                  │\n│                             │  │                                 │\n│  QwenClient                 │  │  DatabaseManager（线程本地连接）│\n│  QwenImageClient            │  │  DatabaseWorker（专用线程）     │\n│  VolcEngineImageClient      │  │  SqlBuilder（参数化查询）       │\n└─────────────────────────────┘  └─────────────────────────────────┘</div>\n</div>')

w('\n<!-- SLIDE 4: ViewModel -->\n<div class="slide-canvas" id="slide-4">\n  <h2>ViewModel 层详解</h2>\n  <p style="font-size:19px;margin-bottom:12px;">UI 层通过 Qt 信号/槽与 ViewModel 通信，ViewModel 持有服务层引用，负责状态管理与缓存，UI 不直接调用服务层。</p>\n  <table>\n    <thead><tr><th>ViewModel</th><th>核心职责</th><th>关键信号</th></tr></thead>\n    <tbody>\n      <tr><td>NovelViewModel</td><td>小说列表 / 当前小说状态管理，封装 CRUD 操作</td><td>novelsLoaded / novelCreated / novelDeleted</td></tr>\n      <tr><td>StoryboardViewModel</td><td>分镜 &amp; 面板状态管理，转发分析进度、图片生成进度到 UI</td><td>analysisProgress / imageGenerationProgress / panelsLoaded</td></tr>\n    </tbody>\n  </table>\n  <table>\n    <thead><tr><th>设计点</th><th>实现</th><th>效果</th></tr></thead>\n    <tbody>\n      <tr><td>单例 + 信号驱动</td><td>UI connect 信号后被动刷新</td><td>无需主动轮询，解耦 UI 与服务层</td></tr>\n      <tr><td>分层缓存</td><td>m_currentPanels 按 novelId + chapterNumber 缓存当前面板列表</td><td>切换章节命中缓存，不重复查库</td></tr>\n      <tr><td>请求令牌防竞态</td><td>异步加载携带 token，回调校验 token 有效性</td><td>快速切换时丢弃过期响应，避免数据错乱</td></tr>\n      <tr><td>QPointer 生命周期守卫</td><td>QtConcurrent::run 回调前检查 guard 是否有效</td><td>防止 ViewModel 销毁后回调访问野指针</td></tr>\n    </tbody>\n  </table>\n</div>')

w('\n<!-- SLIDE 5: Service Layer -->\n<div class="slide-canvas" id="slide-5">\n  <h2>服务层详解</h2>\n  <table>\n    <thead><tr><th>服务</th><th>核心职责</th></tr></thead>\n    <tbody>\n      <tr><td>AnalysisService</td><td>调用 Qwen 流式 API，解析小说文本</td></tr>\n      <tr><td>StoryboardService</td><td>分镜 CRUD，管理面板顺序与内容</td></tr>\n      <tr><td>NovelService</td><td>小说 CRUD，文本读写与状态管理</td></tr>\n      <tr><td>BibleGenerator</td><td>收集角色 / 场景数据，持久化到数据库，图片生成时按需读取</td></tr>\n      <tr><td>CharacterExtractor</td><td>提取、存储、管理角色数据及肖像版本</td></tr>\n      <tr><td>SceneExtractor</td><td>提取、存储、管理场景数据</td></tr>\n      <tr><td>ImageService</td><td>调度图片生成与编辑任务，管理生成状态</td></tr>\n      <tr><td>ExportService</td><td>打包面板图片，生成 PDF / Webtoon / 资源包 (ZIP)</td></tr>\n    </tbody>\n  </table>\n  <blockquote>核心服务不依赖 Qt UI 组件；通过信号通知上层结果</blockquote>\n  <table>\n    <thead><tr><th>设计点</th><th>实现</th><th>效果</th></tr></thead>\n    <tbody>\n      <tr><td>Job 队列异步图片生成</td><td>ImageService 写入 jobs 表，TaskWorker(QThread) 取出执行，进度通过 taskProgress 信号推送</td><td>批量生成不阻塞 UI，进度实时可见</td></tr>\n      <tr><td>双引擎可切换</td><td>QwenImageClient / VolcEngineImageClient 统一接口，配置项切换</td><td>单引擎额度耗尽时无缝切换备用引擎</td></tr>\n      <tr><td>服务间解耦</td><td>服务通过 Qt 信号通知上层，不直接调用其他服务方法</td><td>避免循环依赖，单个服务可独立测试替换</td></tr>\n    </tbody>\n  </table>\n</div>')

w('\n<!-- SLIDE 6: API Client Layer -->\n<div class="slide-canvas" id="slide-6">\n  <h2>API 客户端层详解</h2>\n  <p>文本 AI 使用阿里云 Qwen API，Bearer Token 鉴权，支持 SSE 流式输出，实时推送分析进度。QwenStreamHandler 解析流式 chunk，QwenJsonRepair 修复不完整 JSON，QwenPromptBuilder 统一管理提示词模板。文本分块按段落/句子边界切分（&le;8000字/块），失败后指数退避重试（最多 3 次）。</p>\n  <table>\n    <thead><tr><th>客户端</th><th>服务</th><th>鉴权方式</th></tr></thead>\n    <tbody>\n      <tr><td>QwenImageClient</td><td>阿里云 DashScope</td><td>Bearer Token + 异步轮询</td></tr>\n      <tr><td>VolcEngineImageClient</td><td>火山引擎 Seedream 3.0</td><td>火山引擎 V4 签名（HMAC-SHA256）</td></tr>\n    </tbody>\n  </table>\n</div>')

w('\n<!-- SLIDE 7: Data Layer -->\n<div class="slide-canvas" id="slide-7">\n  <h2>数据层详解</h2>\n  <p>每个线程通过 DatabaseManager 获取独立连接，避免竞态。TransactionScope 用 RAII 管理事务，析构时自动回滚未提交事务。SqlBuilder 核心 CRUD 操作通过占位符构建 SQL，配合 bindValue 绑定参数，杜绝注入风险。</p>\n  <div class="code-block">Windows 主机（Qt 应用）\n    │  连接 &lt;云服务器IP&gt;:3306\n    ▼\n腾讯云服务器\n    │\n    ▼\nWindows Server 2022 — MySQL 8.0.46\n    数据库: qingning_comic</div>\n</div>')

w('\n<!-- SLIDE 8: Data Model Relations -->\n<div class="slide-canvas" id="slide-8">\n  <h2>数据模型设计 — 表关系（10 张表）</h2>\n  <div class="code-block">users（用户）\n  └── novels（小说）\n        ├── storyboards（分镜）\n        │     └── panels（面板）\n        ├── characters（角色）\n        │     └── character_portrait_versions（肖像版本）\n        ├── scenes（场景）\n        ├── jobs（异步任务）\n        ├── change_requests（修改请求）\n        └── exports（导出）</div>\n  <blockquote>novels 是核心主键，所有业务表均通过 novel_id 串联</blockquote>\n  <blockquote>jobs 覆盖 AI 分析、图片生成、导出三类异步任务</blockquote>\n</div>')

w('\n<!-- SLIDE 9: Data Model Fields -->\n<div class="slide-canvas" id="slide-9">\n  <h2>数据模型设计 — 字段设计</h2>\n  <table>\n    <thead><tr><th>分组</th><th>表</th><th>核心设计</th></tr></thead>\n    <tbody>\n      <tr><td rowspan="4">核心业务</td><td>users（用户）</td><td>SHA-256 密码哈希</td></tr>\n      <tr><td>novels（小说）</td><td>status 状态机驱动全流程</td></tr>\n      <tr><td>storyboards（分镜）</td><td>chapter_number 支持多章节</td></tr>\n      <tr><td>panels（面板）</td><td>content JSON + visual_prompt 分离存储</td></tr>\n      <tr><td rowspan="2">AI 任务</td><td>jobs（异步任务）</td><td>持久化状态，支持断点续传和重试</td></tr>\n      <tr><td>change_requests（修改请求）</td><td>原始自然语言 + AI 解析 DSL</td></tr>\n      <tr><td rowspan="2">角色管理</td><td>characters（角色）</td><td>personalities JSON 存性格列表</td></tr>\n      <tr><td>character_portrait_versions（肖像版本）</td><td>version_no 递增，支持版本回退</td></tr>\n      <tr><td rowspan="2">场景 &amp; 导出</td><td>scenes（场景）</td><td>details JSON 存氛围/天气/色调</td></tr>\n      <tr><td>exports（导出）</td><td>file_path + download_url 存本地文件路径</td></tr>\n    </tbody>\n  </table>\n</div>')

w('\n<!-- SLIDE 10: Core Business Flow -->\n<div class="slide-canvas" id="slide-10">\n  <h2>核心业务流程总览</h2>\n  <div class="flow-wrap">\n    <div class="flow-row">\n      <div class="flow-step">① 上传小说文本</div>\n      <div class="flow-arrow">&rarr;</div>\n      <div class="flow-step">② AI 文本分析(SSE 流式)</div>\n      <div class="flow-arrow">&rarr;</div>\n      <div class="flow-step">③ 分镜脚本生成</div>\n      <div class="flow-arrow">&rarr;</div>\n      <div class="flow-step">④ 角色 &amp; 场景提取</div>\n      <div class="flow-arrow">&rarr;</div>\n      <div class="flow-step">⑤ 角色/场景圣经(存入数据库)</div>\n    </div>\n    <div class="flow-row" style="margin-left:360px;">\n      <div class="flow-arrow" style="transform:rotate(90deg);display:inline-block;">&#8595;</div>\n      <div style="margin-left:8px;font-size:15px;color:#64748b;">（③ 分镜脚本生成 也连接到 ⑥）</div>\n    </div>\n    <div class="flow-row">\n      <div class="flow-step">⑥ 图片生成(Job 队列 &middot; 读取圣经注入 Prompt)</div>\n      <div class="flow-arrow">&rarr;</div>\n      <div class="flow-step">⑦ 图片写入本地磁盘(路径写回数据库)</div>\n      <div class="flow-arrow">&rarr;</div>\n      <div class="flow-step">⑧ 多格式导出(PDF / Webtoon)</div>\n    </div>\n  </div>\n  <table style="font-size:17px;">\n    <thead><tr><th>步骤</th><th>核心类</th><th>关键技术</th></tr></thead>\n    <tbody>\n      <tr><td>① 上传</td><td>NovelService</td><td>文件读取 + MySQL 持久化</td></tr>\n      <tr><td>② 分析</td><td>AnalysisService + QwenClient</td><td>SSE 流式 + 文本分块（8000字/块）</td></tr>\n      <tr><td>③ 分镜</td><td>StoryboardService</td><td>JSON Schema 驱动 + 多块合并</td></tr>\n      <tr><td>④ 提取</td><td>CharacterExtractor / SceneExtractor</td><td>AI 结构化输出 + 去重</td></tr>\n      <tr><td>⑤ 圣经</td><td>BibleGenerator</td><td>角色/场景数据持久化，图片生成时按需读取</td></tr>\n      <tr><td>⑥ 图片</td><td>ImageService + Job 系统</td><td>QThread 异步队列，双引擎可选（阿里云 / 火山引擎）</td></tr>\n      <tr><td>⑦ 存储</td><td>FileStorage</td><td>图片写入本地磁盘，路径写回数据库</td></tr>\n      <tr><td>⑧ 导出</td><td>ExportService</td><td>PDF / Webtoon / 资源包</td></tr>\n    </tbody>\n  </table>\n</div>')

w('\n<!-- SLIDE 11: Flow Detail 1&2 -->\n<div class="slide-canvas" id="slide-11">\n  <h2>流程详解 ①② — 上传 &amp; AI 文本分析（SSE 流式）</h2>\n  <p>用户选择本地 .txt 文件，填写标题后提交。系统自动检测编码（UTF-8 / GBK），读取文件内容写入 novels 表，返回 novel_id，后续所有步骤均以 novel_id 为主键串联。</p>\n  <p>小说文本可达数万字，超出 Qwen API 单次 token 限制（约 8000 字）。splitTextIntelligently() 按段落边界切分，超长段落按句子二次切分，逐块调用 API。每块返回 SSE 流，QwenStreamHandler 在独立线程实时推送进度到 UI。第一块携带已有角色/场景历史数据，后续块只带空数组，避免重复传大量上下文。QwenJsonRepair 修复流式 JSON 末尾截断问题，失败后指数退避重试（最多 3 次）。</p>\n</div>')

w('\n<!-- SLIDE 12: Flow Detail 3&4 -->\n<div class="slide-canvas" id="slide-12">\n  <h2>流程详解 ③④ — 分镜生成 &amp; 角色/场景提取</h2>\n  <p>分析完成后，QwenStoryboardMerger::mergeStoryboards() 合并所有块的 panels 数组，重新计算页码（每页 6 个面板），写入 panels 表。与此同时，CharacterExtractor 提取角色的 name / description / appearance，跨块去重后写入 characters 表；SceneExtractor 提取 location / time / atmosphere，写入 scenes 表。Prompt 由 SchemaToPrompt::buildSystemPrompt() 将 storyboard.json Schema 自动转换生成，保证输出结构严格可解析。</p>\n</div>')

w('\n<!-- SLIDE 13: Flow Detail 5 -->\n<div class="slide-canvas" id="slide-13">\n  <h2>流程详解 ⑤ — 角色/场景圣经（Bible）</h2>\n  <p>圣经是角色与场景的结构化摘要，图片生成时按需读取，保证跨面板角色外貌、场景描述一致。BibleGenerator 读取 characters 表生成角色圣经（name / appearance / personality / role），读取 scenes 表生成场景圣经（name / location / atmosphere / time_of_day），持久化到数据库。图片生成时，ImageService 调用 fetchCharacterRefs() / fetchSceneRefs() 按 novelId 查询，注入 buildPromptForPanel()。</p>\n</div>')

w('\n<!-- SLIDE 14: Flow Detail 6 -->\n<div class="slide-canvas" id="slide-14">\n  <h2>流程详解 ⑥ — 图片生成（Job 异步队列）</h2>\n  <p>图片生成单张耗时 10~30s，批量生成会阻塞 UI。UI 点击批量生成后，ImageService 通过 TaskQueue 将任务写入 jobs 表（status=pending）并入队。TaskWorker（QThread）从队列取出任务，调用图像 API，完成后写入图片路径并更新 jobs 表状态。进度通过 taskProgress 信号实时推送到 UI，无需轮询。</p>\n</div>')

w('\n<!-- SLIDE 15: Flow Detail 7&8 -->\n<div class="slide-canvas" id="slide-15">\n  <h2>流程详解 ⑦⑧ — 存储 &amp; 导出</h2>\n  <p>图片生成完成后（Base64），解码写入本地磁盘，文件路径写回 panels.preview_image_path / hd_image_path，UI 通过 AsyncImageLoader 异步加载并本地缓存。导出由 ExportService 处理：PDF 用 QPainter + QPdfWriter，Webtoon 用 QImage 拼接竖屏长图，资源包用自实现 ZIP 打包（无第三方依赖）。</p>\n</div>')

w('\n<!-- SLIDE 16: Thank you -->\n<div class="slide-canvas" id="slide-16">\n  <div class="cover-center" style="align-items:center;justify-content:center;width:100%;">\n    <h1 style="font-size:96px;text-align:center;">感谢聆听</h1>\n  </div>\n</div>')

w('\n</div><!-- #stage -->\n\n<!-- Navigation dots -->\n<div id="nav-dots">\n  <div class="dot active" onclick="goTo(0)"></div>\n  <div class="dot" onclick="goTo(1)"></div>\n  <div class="dot" onclick="goTo(2)"></div>\n  <div class="dot" onclick="goTo(3)"></div>\n  <div class="dot" onclick="goTo(4)"></div>\n  <div class="dot" onclick="goTo(5)"></div>\n  <div class="dot" onclick="goTo(6)"></div>\n  <div class="dot" onclick="goTo(7)"></div>\n  <div class="dot" onclick="goTo(8)"></div>\n  <div class="dot" onclick="goTo(9)"></div>\n  <div class="dot" onclick="goTo(10)"></div>\n  <div class="dot" onclick="goTo(11)"></div>\n  <div class="dot" onclick="goTo(12)"></div>\n  <div class="dot" onclick="goTo(13)"></div>\n  <div class="dot" onclick="goTo(14)"></div>\n  <div class="dot" onclick="goTo(15)"></div>\n</div>\n<button id="nav-prev" onclick="prev()">&larr; 上一页</button>\n<button id="nav-next" onclick="next()">下一页 &rarr;</button>\n<div id="slide-counter">1 / 16</div>\n\n<script>\nvar current = 0;\nvar total = 16;\nvar slides = document.querySelectorAll(\'.slide-canvas\');\nvar dots = document.querySelectorAll(\'.dot\');\nvar counter = document.getElementById(\'slide-counter\');\n\nfunction goTo(n) {\n  slides[current].classList.remove(\'active\');\n  dots[current].classList.remove(\'active\');\n  current = (n + total) % total;\n  slides[current].classList.add(\'active\');\n  dots[current].classList.add(\'active\');\n  counter.textContent = (current + 1) + \' / \' + total;\n}\nfunction next() { goTo(current + 1); }\nfunction prev() { goTo(current - 1); }\n\ndocument.addEventListener(\'keydown\', function(e) {\n  if (e.key === \'ArrowRight\' || e.key === \'ArrowDown\') next();\n  if (e.key === \'ArrowLeft\'  || e.key === \'ArrowUp\')   prev();\n});\n\nfunction scaleSlides() {\n  var sw = window.innerWidth;\n  var sh = window.innerHeight;\n  var scaleX = sw / 1920;\n  var scaleY = sh / 1080;\n  var scale = Math.min(scaleX, scaleY);\n  slides.forEach(function(s) {\n    s.style.transform = \'scale(\' + scale + \')\';\n  });\n}\nwindow.addEventListener(\'resize\', scaleSlides);\nscaleSlides();\n</script>\n</body>\n</html>')


